Now, create a `script.js` file and add the following code to fetch data fro
from an API, display it in a chart, and show values in a table:

```javascript
// Fetching Data from API
const apiUrl = 'https://api.cryptofinancehub.com/api/v1/inflation-rates';

fetch(apiUrl)
    .then(response => response.json())
    .then(data => {
        const inflationData = data.map((item, index) => ({
            date: new Date(item.date).toLocaleDateString('en-US'),
            inflationRate: item.inflation_rate,
        }));

        // Displaying Data in Chart
        const ctx = document.getElementById('inflationChart').getContext('2
document.getElementById('inflationChart').getContext('2d');
        const chart = new Chart(ctx, {
            type: 'line',
            data: {
                labels: inflationData.map(item => item.date),
                datasets: [{
                    label: 'Inflation Rate (%)',
                    data: inflationData.map(item => item.inflationRate),
                    borderColor: 'rgba(255, 99, 132, 1)',
                    tension: 0.2,
                }],
            },
            options: {
                scales: {
                    yAxes: [{
                        ticks: {
                            beginAtZero: true
                        }
                    }]
                }
            }
        });

        // Displaying Data in Table
        const tableBody = document.getElementById('inflationData');
        inflationData.forEach(item => {
            const row = document.createElement('tr');
            row.innerHTML = `
                <td>${item.date}</td>
                <td>${item.inflationRate.toFixed(2)}%</td>
            `;
            tableBody.appendChild(row);
        });
    })
    .catch(error => console.error(error));
```

Please note that you need to replace the `apiUrl` with your actual API endp
endpoint.

